mapper.select:
select dbo.getCommonName('area', a.area_cd) as area_cd ,dbo.getItemName(a.item_cd) as item_name ,b.mat_no ,b.lot_no ,b.lot_no2 ,b.batch_status ,isnull(m.test_state, 'N') as test_state ,m.qc_proc_test_type ,c.proc_order_date as charging_date ,d.proc_order_date as packing_date ,b.work_batch_id from TB_WORK_ORDER_MST a inner join TB_WORK_ORDER_BATCH b on b.work_order_id = a.work_order_id left outer join tb_qc_proc_test_mst m on m.work_batch_id = b.work_batch_id inner join TB_WORK_ORDER_PROC c on c.work_batch_id = b.work_batch_id and c.proc_cd = 'PRC004' inner join TB_WORK_ORDER_PROC d on d.work_batch_id = b.work_batch_id and d.proc_cd = 'PRC005' where 1=1 --b.batch_status != '99' and b.batch_status >= '22' and d.proc_order_date between #{strDate} and #{endDate}
and a.area_cd = #{areaCd}
and a.item_cd = #{itemCd}
and b.batch_status = #{batchStatus}
and m.test_state) =#{testState}
order by a.work_order_date desc, a.seq desc
